#include <iostream>
#include <algorithm>

int main() {
    int n;
    std::cin >> n;
    int arr[1000];
    for (int i = 0; i < n; i++) {
        std::cin >> arr[i];
    }
    int dp[1000];
    for (int i = 0; i < n; i++) {
        dp[i] = 1;
        for (int j = 0; j < i; j++) {
            if (arr[j] < arr[i]) {
                dp[i] = std::max(dp[i], dp[j] + 1);
            }
        }
    }
    int maxLen = 0;
    for (int i = 0; i < n; i++) {
        maxLen = std::max(maxLen, dp[i]);
    }
    std::cout << maxLen << std::endl;
    return 0;
}
